    .portfolio-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:18px;margin-top:32px}.work{background:#fff;border:1px solid var(--line);border-radius:18px;overflow:hidden;box-shadow:0 14px 42px rgba(7,27,58,.055);transition:.22s ease;display:flex;flex-direction:column}.work:hover{transform:translateY(-4px);box-shadow:var(--shadow);border-color:#CFE0FF}.work-screen{height:178px;background:linear-gradient(135deg,#071B3A,#1468FF);padding:10px;position:relative;overflow:hidden}.work-screen:after{content:"";position:absolute;right:-38px;top:-38px;width:130px;height:130px;border-radius:50%;background:rgba(25,195,125,.34)}.work-screen img{position:relative;z-index:1;width:100%;height:100%;object-fit:cover;object-position:top center;border-radius:12px;box-shadow:0 12px 28px rgba(7,27,58,.18);background:#fff}.work-body{padding:18px;display:flex;flex-direction:column;flex:1}.work-body span{font-size:11px;font-weight:800;color:var(--blue);letter-spacing:.08em;text-transform:uppercase}.work-body h3{margin-top:6px}.work-body p{font-size:13px;margin-top:10px}.work-link{display:inline-flex;align-items:center;gap:6px;margin-top:auto;padding-top:16px;font-size:12px;font-weight:800;color:var(--navy)}.work-link:hover{color:var(--blue)}
