  <script>

    function sendWhatsApp(event){
      event.preventDefault();
      const form = event.currentTarget;
      const data = new FormData(form);
      const servicios = data.getAll('servicios');
      const resumen = [
        'Hola ActivaWeb, quiero cotizar un proyecto web.',
        '',
        'Nombre: ' + (data.get('nombre') || ''),
        'Empresa: ' + (data.get('empresa') || 'No indicada'),
        'Teléfono: ' + (data.get('telefono') || ''),
        'Correo: ' + (data.get('correo') || 'No indicado'),
        'Servicios: ' + (servicios.length ? servicios.join(', ') : 'No indicado'),
        'Presupuesto: ' + (data.get('presupuesto') || 'Por definir'),
        'Plazo ideal: ' + (data.get('plazo') || 'Por definir'),
        '',
        'Detalle del proyecto:',
        data.get('mensaje') || ''
      ].join('\n');
      window.open('https://wa.me/56952157840?text=' + encodeURIComponent(resumen), '_blank');
    }

    document.querySelectorAll('.faq-q').forEach(btn=>btn.addEventListener('click',()=>btn.parentElement.classList.toggle('active')));
  </script>
